{"code": "import os
import yaml
import sys

config_path = os.path.expanduser('~/.hermes/config.yaml')
with open(config_path, 'r') as f:
    config = yaml.safe_load(f)

# Read .env file
env_path = os.path.expanduser('~/.hermes/.env')
env_vars = {}
with open(env_path, 'r') as f:
    for line in f:
        line = line.strip()
        if line and not line.startswith('#') and '=' in line:
            key, value = line.split('=', 1)
            env_vars[key] = value

print('WEIXIN_ACCOUNT_ID:', env_vars.get('WEIXIN_ACCOUNT_ID', 'not found'))
print('WEIXIN_TOKEN:', env_vars.get('WEIXIN_TOKEN', 'not found'))
print('WEIXIN_BASE_URL:', env_vars.get('WEIXIN_BASE_URL', 'not found'))

# Ensure platforms key exists
if 'platforms' not in config:
    config['platforms'] = {}

# Add weixin config
config['platforms']['weixin'] = {
    'extra': {
        'account_id': env_vars.get('WEIXIN_ACCOUNT_ID'),
        'token': env_vars.get('WEIXIN_TOKEN'),
        'base_url': env_vars.get('WEIXIN_BASE_URL', 'https://ilinkai.weixin.qq.com')
    }
}

# Write back
with open(config_path, 'w') as f:
    yaml.dump(config, f, default_flow_style=False, sort_keys=False)

print('Config updated successfully.')"}

